const express = require('express');
const redis = require('redis');
const client = redis.createClient({ url: process.env.REDIS_URL });

const app = express();

app.get('/hit', async (req, res) => {
  // Atomic increment - no race condition possible
  const count = await client.incr('global_counter');
  res.send(`Visitor #${count}`);
});

client.connect().then(() => {
  app.listen(3000, () => console.log('Instance started'));
});
